import React, { useState, useEffect, useRef } from "react";
import { NavLink, useNavigate } from "react-router-dom";

/* ═══════════════════════════════════════════════════════════
   STYLES
═══════════════════════════════════════════════════════════ */
const NAV_CSS = `
  @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,700;0,900;1,700&family=DM+Sans:wght@300;400;500;600;700&display=swap');

  :root {
    --nav-bg:     #0d0800;
    --nav-border: rgba(200,134,26,0.18);
    --amber:      #c8861a;
    --amber-l:    #e8a840;
    --amber-xs:   rgba(200,134,26,0.12);
    --text:       #f0e0c0;
    --muted:      #9a7a55;
    --dim:        #4a3020;
    --white:      #ffffff;
  }

  .nav-root {
    position: sticky;
    top: 0;
    z-index: 9000;
    background: rgba(13, 8, 0, 0.97);
    backdrop-filter: blur(20px);
    -webkit-backdrop-filter: blur(20px);
    border-bottom: 1px solid var(--nav-border);
    font-family: 'DM Sans', sans-serif;
    transition: box-shadow 0.3s ease;
  }
  .nav-root.scrolled {
    box-shadow: 0 4px 32px rgba(200,134,26,0.1);
  }

  .nav-inner {
    max-width: 1340px;
    margin: 0 auto;
    padding: 0 48px;
    height: 70px;
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 24px;
  }

  /* ── LOGO ── */
  .nav-logo {
    display: flex;
    align-items: center;
    gap: 10px;
    text-decoration: none;
    flex-shrink: 0;
  }
  .nav-logo-icon {
    width: 40px; height: 40px;
    background: linear-gradient(135deg, var(--amber), #8b5000);
    border-radius: 12px;
    display: flex; align-items: center; justify-content: center;
    font-size: 1.2rem;
    box-shadow: 0 4px 16px rgba(200,134,26,0.3);
    flex-shrink: 0;
  }
  .nav-logo-text {
    font-family: 'Playfair Display', serif;
    font-size: 1.4rem;
    font-weight: 900;
    color: var(--text);
    letter-spacing: -0.5px;
  }
  .nav-logo-text span { color: var(--amber); }

  /* ── LINKS ── */
  .nav-links {
    display: flex;
    align-items: center;
    gap: 2px;
    list-style: none;
  }
  .nav-links li a,
  .nav-links li button {
    padding: 8px 14px;
    border-radius: 50px;
    font-size: 0.85rem;
    font-weight: 500;
    color: var(--muted);
    text-decoration: none;
    border: none;
    background: none;
    cursor: pointer;
    font-family: 'DM Sans', sans-serif;
    transition: all 0.22s;
    display: flex;
    align-items: center;
    gap: 6px;
    white-space: nowrap;
    position: relative;
  }
  .nav-links li a:hover,
  .nav-links li button:hover {
    color: var(--amber-l);
    background: var(--amber-xs);
    text-decoration: none;
  }
  .nav-links li a.active {
    color: var(--amber-l);
    background: var(--amber-xs);
  }

  /* ── DROPDOWN ── */
  .nav-dropdown {
    position: relative;
  }
  .nav-dropdown-menu {
    position: absolute;
    top: calc(100% + 12px);
    left: 50%;
    transform: translateX(-50%);
    background: #1a1000;
    border: 1px solid var(--nav-border);
    border-radius: 18px;
    padding: 10px;
    min-width: 200px;
    box-shadow: 0 24px 60px rgba(0,0,0,0.5);
    display: none;
    flex-direction: column;
    gap: 2px;
    z-index: 100;
  }
  .nav-dropdown:hover .nav-dropdown-menu {
    display: flex;
  }
  .nav-dropdown-menu a {
    padding: 10px 14px !important;
    border-radius: 12px !important;
    color: var(--muted) !important;
    font-size: 0.85rem !important;
    text-decoration: none;
    display: flex !important;
    align-items: center !important;
    gap: 8px !important;
    transition: all 0.2s !important;
  }
  .nav-dropdown-menu a:hover {
    background: var(--amber-xs) !important;
    color: var(--amber-l) !important;
  }

  /* ── CART BADGE ── */
  .nav-cart-badge {
    position: absolute;
    top: -4px; right: -4px;
    width: 17px; height: 17px;
    background: var(--amber);
    color: white;
    border-radius: 50%;
    font-size: 0.6rem;
    font-weight: 700;
    display: flex; align-items: center; justify-content: center;
    border: 2px solid var(--nav-bg);
  }

  /* ── RIGHT ACTIONS ── */
  .nav-actions {
    display: flex;
    align-items: center;
    gap: 8px;
    flex-shrink: 0;
  }
  .nav-icon-btn {
    width: 40px; height: 40px;
    border-radius: 12px;
    border: 1px solid var(--nav-border);
    background: transparent;
    color: var(--muted);
    font-size: 1.1rem;
    cursor: pointer;
    display: flex; align-items: center; justify-content: center;
    transition: all 0.22s;
    position: relative;
    text-decoration: none;
    font-family: 'DM Sans', sans-serif;
  }
  .nav-icon-btn:hover {
    background: var(--amber-xs);
    border-color: var(--amber);
    color: var(--amber-l);
    text-decoration: none;
  }
  .nav-btn-primary {
    padding: 9px 22px;
    background: linear-gradient(135deg, var(--amber), #8b5000);
    color: white !important;
    border: none;
    border-radius: 50px;
    font-size: 0.85rem;
    font-weight: 700;
    cursor: pointer;
    font-family: 'DM Sans', sans-serif;
    transition: all 0.22s;
    box-shadow: 0 4px 16px rgba(200,134,26,0.3);
    text-decoration: none;
    display: inline-flex;
    align-items: center;
    gap: 6px;
    white-space: nowrap;
  }
  .nav-btn-primary:hover {
    box-shadow: 0 8px 28px rgba(200,134,26,0.45);
    transform: translateY(-1px);
    color: white !important;
    text-decoration: none;
  }
  .nav-btn-outline {
    padding: 8px 18px;
    background: transparent;
    color: var(--muted);
    border: 1px solid var(--nav-border);
    border-radius: 50px;
    font-size: 0.85rem;
    font-weight: 500;
    cursor: pointer;
    font-family: 'DM Sans', sans-serif;
    transition: all 0.22s;
    text-decoration: none;
    display: inline-flex;
    align-items: center;
    gap: 6px;
  }
  .nav-btn-outline:hover {
    border-color: var(--amber);
    color: var(--amber-l);
    text-decoration: none;
  }

  /* ── USER MENU DROPDOWN ── */
  .nav-user-wrap {
    position: relative;
  }
  .nav-user-menu {
    position: absolute;
    top: calc(100% + 12px);
    right: 0;
    background: #1a1000;
    border: 1px solid var(--nav-border);
    border-radius: 18px;
    padding: 10px;
    min-width: 200px;
    box-shadow: 0 24px 60px rgba(0,0,0,0.5);
    display: none;
    flex-direction: column;
    gap: 2px;
    z-index: 100;
  }
  .nav-user-wrap.open .nav-user-menu {
    display: flex;
  }
  .nav-user-menu a,
  .nav-user-menu button {
    padding: 10px 14px;
    border-radius: 12px;
    color: var(--muted);
    font-size: 0.85rem;
    font-weight: 500;
    text-decoration: none;
    display: flex;
    align-items: center;
    gap: 8px;
    transition: all 0.2s;
    border: none;
    background: none;
    cursor: pointer;
    font-family: 'DM Sans', sans-serif;
    text-align: left;
    width: 100%;
  }
  .nav-user-menu a:hover,
  .nav-user-menu button:hover {
    background: var(--amber-xs);
    color: var(--amber-l);
    text-decoration: none;
  }
  .nav-user-divider {
    height: 1px;
    background: var(--nav-border);
    margin: 6px 4px;
  }
  .nav-logout-btn {
    color: #ff7a7a !important;
  }
  .nav-logout-btn:hover {
    background: rgba(255,100,100,0.1) !important;
    color: #ff9090 !important;
  }

  /* ── MOBILE HAMBURGER ── */
  .nav-hamburger {
    display: none;
    flex-direction: column;
    gap: 5px;
    width: 36px; height: 36px;
    align-items: center; justify-content: center;
    background: none;
    border: 1px solid var(--nav-border);
    border-radius: 10px;
    cursor: pointer;
    padding: 0;
    transition: all 0.22s;
  }
  .nav-hamburger:hover { border-color: var(--amber); background: var(--amber-xs); }
  .nav-hamburger span {
    display: block;
    width: 18px; height: 2px;
    background: var(--muted);
    border-radius: 2px;
    transition: all 0.3s;
  }
  .nav-hamburger.open span:nth-child(1) { transform: translateY(7px) rotate(45deg); }
  .nav-hamburger.open span:nth-child(2) { opacity: 0; }
  .nav-hamburger.open span:nth-child(3) { transform: translateY(-7px) rotate(-45deg); }

  /* ── MOBILE MENU ── */
  .nav-mobile-menu {
    display: none;
    flex-direction: column;
    background: #110b00;
    border-top: 1px solid var(--nav-border);
    padding: 16px;
    gap: 4px;
    max-height: 0;
    overflow: hidden;
    transition: max-height 0.4s ease, padding 0.3s ease;
  }
  .nav-mobile-menu.open {
    display: flex;
    max-height: 600px;
  }
  .nav-mobile-link {
    padding: 12px 16px;
    border-radius: 12px;
    color: var(--muted);
    text-decoration: none;
    font-size: 0.9rem;
    font-weight: 500;
    font-family: 'DM Sans', sans-serif;
    transition: all 0.22s;
    display: flex;
    align-items: center;
    gap: 10px;
    border: none;
    background: none;
    cursor: pointer;
    width: 100%;
    text-align: left;
  }
  .nav-mobile-link:hover,
  .nav-mobile-link.active {
    background: var(--amber-xs);
    color: var(--amber-l);
    text-decoration: none;
  }
  .nav-mobile-divider {
    height: 1px;
    background: var(--nav-border);
    margin: 6px 0;
  }
  .nav-mobile-actions {
    display: flex;
    gap: 10px;
    padding: 10px 4px 4px;
    flex-wrap: wrap;
  }

  /* ── RESPONSIVE ── */
  @media (max-width: 1024px) {
    .nav-links { display: none; }
    .nav-hamburger { display: flex; }
    .nav-inner { padding: 0 20px; }
  }
  @media (max-width: 480px) {
    .nav-btn-primary { padding: 8px 14px; font-size: 0.8rem; }
    .nav-btn-outline  { display: none; }
  }
`;

/* ═══════════════════════════════════════════════════════════
   COMPONENT
═══════════════════════════════════════════════════════════ */
export default function Nav() {
  // ── ALL HOOKS AT TOP — unconditional, same order every render ──
  const navigate        = useNavigate();                 // ✅ always called here
  const [scrolled,    setScrolled]    = useState(false);
  const [mobileOpen,  setMobileOpen]  = useState(false);
  const [userOpen,    setUserOpen]    = useState(false);
  const [cartCount,   setCartCount]   = useState(0);
  const [isLoggedIn,  setIsLoggedIn]  = useState(false);
  const [userName,    setUserName]    = useState("");
  const userRef = useRef(null);

  // ── scroll effect ──
  useEffect(() => {
    const h = () => setScrolled(window.scrollY > 20);
    window.addEventListener("scroll", h);
    return () => window.removeEventListener("scroll", h);
  }, []);

  // ── read localStorage for login state ──
  useEffect(() => {
    try {
      const uid  = localStorage.getItem("uid");
      const name = localStorage.getItem("uname") || localStorage.getItem("name") || "";
      setIsLoggedIn(!!uid);
      setUserName(name);

      // cart count
      const cart = localStorage.getItem("cartCount");
      setCartCount(cart ? parseInt(cart) : 0);
    } catch (e) {
      // localStorage unavailable — leave defaults
    }
  }, []);

  // ── close user menu on outside click ──
  useEffect(() => {
    const h = (e) => {
      if (userRef.current && !userRef.current.contains(e.target)) {
        setUserOpen(false);
      }
    };
    document.addEventListener("mousedown", h);
    return () => document.removeEventListener("mousedown", h);
  }, []);

  // ── close mobile menu on route change ──
  useEffect(() => {
    setMobileOpen(false);
    setUserOpen(false);
  }, []);

  // ── logout handler ──
  const handleLogout = () => {
    try {
      localStorage.removeItem("uid");
      localStorage.removeItem("uname");
      localStorage.removeItem("name");
    } catch (e) {}
    setIsLoggedIn(false);
    setUserOpen(false);
    setMobileOpen(false);
    navigate("/");
  };

  const NAV_LINKS = [
    { to: "/",         label: "Home",       icon: "🏠" },
    { to: "/service",  label: "Service",    icon: "🩺" },
    { to: "/gallery",  label: "Pet Gallery",icon: "🖼️" },
    { to: "/clinic",   label: "Clinic",     icon: "🏥" },
    { to: "/product",  label: "Products",   icon: "🛍️" },
    { to: "/contact",  label: "Contact Us", icon: "📞" },
  ];

  return (
    <>
      <style dangerouslySetInnerHTML={{ __html: NAV_CSS }} />

      <nav className={`nav-root${scrolled ? " scrolled" : ""}`}>
        <div className="nav-inner">

          {/* ── LOGO ── */}
          <NavLink to="/" className="nav-logo" onClick={() => setMobileOpen(false)}>
            <div className="nav-logo-icon">🐾</div>
            <span className="nav-logo-text">Pet<span>ology</span></span>
          </NavLink>

          {/* ── DESKTOP LINKS ── */}
          <ul className="nav-links">
            {NAV_LINKS.map(link => (
              <li key={link.to}>
                <NavLink
                  to={link.to}
                  end={link.to === "/"}
                  className={({ isActive }) => isActive ? "active" : ""}
                >
                  {link.label}
                </NavLink>
              </li>
            ))}
          </ul>

          {/* ── RIGHT ACTIONS ── */}
          <div className="nav-actions">
            {/* Cart */}
            <NavLink to="/cart" className="nav-icon-btn" title="Cart">
              🛒
              {cartCount > 0 && (
                <span className="nav-cart-badge">{cartCount}</span>
              )}
            </NavLink>

            {/* My Orders */}
            <NavLink to="/myorders" className="nav-icon-btn" title="My Orders">
              📦
            </NavLink>

            {/* Login / User */}
            {isLoggedIn ? (
              <div className={`nav-user-wrap${userOpen ? " open" : ""}`} ref={userRef}>
                <button
                  className="nav-icon-btn"
                  onClick={() => setUserOpen(o => !o)}
                  title={userName || "Account"}
                  style={{ fontWeight: 700, fontSize: "0.85rem", width: "auto", padding: "0 14px", gap: 6 }}
                >
                  👤 {userName ? userName.split(" ")[0] : "Account"}
                </button>
                <div className="nav-user-menu">
                  <NavLink to="/account" onClick={() => setUserOpen(false)}>👤 My Profile</NavLink>
                  <NavLink to="/myorders" onClick={() => setUserOpen(false)}>📦 My Orders</NavLink>
                  <NavLink to="/cart" onClick={() => setUserOpen(false)}>🛒 Cart</NavLink>
                  <div className="nav-user-divider" />
                  <button className="nav-logout-btn" onClick={handleLogout}>🚪 Logout</button>
                </div>
              </div>
            ) : (
              <>
                <NavLink to="/login" className="nav-btn-outline">Login</NavLink>
                <NavLink to="/signup" className="nav-btn-primary">Buy Now 🐾</NavLink>
              </>
            )}

            {/* Hamburger */}
            <button
              className={`nav-hamburger${mobileOpen ? " open" : ""}`}
              onClick={() => setMobileOpen(o => !o)}
              aria-label="Menu"
            >
              <span /><span /><span />
            </button>
          </div>
        </div>

        {/* ── MOBILE MENU ── */}
        <div className={`nav-mobile-menu${mobileOpen ? " open" : ""}`}>
          {NAV_LINKS.map(link => (
            <NavLink
              key={link.to}
              to={link.to}
              end={link.to === "/"}
              className={({ isActive }) =>
                `nav-mobile-link${isActive ? " active" : ""}`
              }
              onClick={() => setMobileOpen(false)}
            >
              {link.icon} {link.label}
            </NavLink>
          ))}

          <div className="nav-mobile-divider" />
          <NavLink to="/cart"     className="nav-mobile-link" onClick={() => setMobileOpen(false)}>🛒 Cart {cartCount > 0 && `(${cartCount})`}</NavLink>
          <NavLink to="/myorders" className="nav-mobile-link" onClick={() => setMobileOpen(false)}>📦 My Orders</NavLink>

          <div className="nav-mobile-divider" />
          <div className="nav-mobile-actions">
            {isLoggedIn ? (
              <button
                className="nav-btn-outline"
                style={{ border: "1px solid rgba(255,100,100,0.3)", color: "#ff7a7a" }}
                onClick={handleLogout}
              >
                🚪 Logout
              </button>
            ) : (
              <>
                <NavLink to="/login"  className="nav-btn-outline" onClick={() => setMobileOpen(false)}>Login</NavLink>
                <NavLink to="/signup" className="nav-btn-primary" onClick={() => setMobileOpen(false)}>Buy Now 🐾</NavLink>
              </>
            )}
          </div>
        </div>
      </nav>
    </>
  );
}
